import React, { useRef, useEffect, useState } from 'react';

const DynamicCanvasCrop = ({ src, cropData, alt, ...props }) => {
  const canvasRef = useRef(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(false);

  useEffect(() => {
    if (!src || !cropData) {
      setError(true);
      return;
    }

    let parsedCrop;
    try {
      parsedCrop = JSON.parse(cropData).cropBox; 
    } catch (e) {
      setError(true);
      return;
    }

    if (!parsedCrop || !parsedCrop.width || !parsedCrop.height) {
      setError(true);
      return;
    }

    const image = new Image();
    image.crossOrigin = 'anonymous'; 
    image.src = src;

    image.onload = () => {
      const canvas = canvasRef.current;
      const ctx = canvas.getContext('2d');

      const imageWidth = image.naturalWidth;
      const imageHeight = image.naturalHeight;

      let pixelX = (parsedCrop.x / 100) * imageWidth;
      let pixelY = (parsedCrop.y / 100) * imageHeight;
      let pixelWidth = (parsedCrop.width / 100) * imageWidth;
      let pixelHeight = (parsedCrop.height / 100) * imageHeight;

      // FIX 3: THE SAFETY NET. If the old broken data was saved in pixels instead of %,
      // this stops the canvas from becoming 5,000px wide and destroying the CSS layout.
      if (pixelWidth > imageWidth || isNaN(pixelWidth)) {
        pixelX = 0;
        pixelY = 0;
        pixelWidth = imageWidth;
        pixelHeight = imageHeight;
      }

      canvas.width = pixelWidth;
      canvas.height = pixelHeight;

      ctx.drawImage(
        image,
        pixelX, pixelY, 
        pixelWidth, pixelHeight, 
        0, 0, 
        pixelWidth, pixelHeight 
      );

      setLoading(false);
    };

    image.onerror = () => { setError(true); };

  }, [src, cropData]); 

  if (error) {
    return (
      <img
        src="https://images.unsplash.com/photo-1552820728-8b83bb6b773f?q=80&w=500"
        alt="Image not found"
        style={{ width: '100%', height: '100%', objectFit: 'cover' }}
      />
    );
  }

  if (loading) {
    return <div style={{ width: '100%', height: '100%', backgroundColor: '#0a0a0a' }} />
  }

  return <canvas ref={canvasRef} alt={alt} {...props} />;
};

export default DynamicCanvasCrop;
